import React, { useEffect, useState } from 'react'
import { useStaticQuery, graphql } from 'gatsby'
import produce from 'immer'

import Layout from "../components/layout"
import PageTitle from '../components/ui/pageTitle'
import Hash from '../components/hash'
import '../components/blog/blog.scss'


export default function Blog() {
  const [cates, setCates] = useState(['All'])
  const [post, setPost] = useState({
    defData: [],
    searchData: []
  })
  const { allMarkdownRemark: { edges: posts } } = useStaticQuery(graphql`
    query MyQuery {
      allMarkdownRemark {
        edges {
          node {
            frontmatter {
              title
              category
              subtitle
            }
            excerpt
          }
        }
      }
    }
  `)

  const OnScroll = () => {
    const top = window.scrollY
    const btm = top + window.innerHeight;

    [...document.getElementsByClassName('blogItem')].forEach(item => {
      const mid = item.offsetTop + item.offsetHeight / 2

      if (top + 70 <= mid && mid <= btm - 60) {
        item.classList.add('active')
      } else {
        item.classList.remove('active')
      }
    })
  }

  const categoryHandle = (data) => {
    const res = post.defData.filter(v => v.category.filter(item => data.includes(item)).length)

    setPost(produce(v => {
      v.searchData = data[0] === 'All' ? post.defData : res
    }))
  }


  useEffect(() => {
    window.addEventListener('scroll', () => {
      OnScroll()
    })
  }, [])

  useEffect(() => {
    setCates(['All', ...posts.reduce((stack, now) => [...new Set([...now.node.frontmatter.category.split(', '), ...stack])], [])])
    setPost(produce(v => {
      const data = posts.map(({node}) => {
        const fm = node.frontmatter
  
        return {
          category: fm.category.split(', '),
          title: fm.title,
          subtitle: fm.subtitle,
          content: node.excerpt
        }
      })

      v.defData = data
      v.searchData = data
    }))
  }, [posts])


  return (
    <div className="blog">
      <PageTitle 
        title="Blog"
        info="하루 한개 포스팅을 목표로 하고있어요."
        category={{
          data: cates,
          handle: categoryHandle
        }}
      />

      <div className="postList" ref={OnScroll}>
        {[...post.searchData, ...post.searchData].map((item, i) => (
          <div className="blogItem item" key={i}>
            <div className="category">{item.category.join(' & ')}</div>
            <div className="title">{item.title}</div>
            <div className="subTitle">{item.subtitle}</div>
            <div className="previewTxt">{item.content}</div>
          </div>
        ))}
      </div>

      <Hash />
    </div>
  )
}