import React from 'react'

import Category from '../../category'

import './pageTitle.scss'


export default function PageTitle({ title = '', info = '', category = {} }) {
  return (
    <div className="pageTitle">
      <h2>{title}</h2>
      <p>{info}</p>

      {category?.data ? (
        <Category
          data={category.data} 
          activeCate={category.actives}
          clickHandle={category.handle}
        />
      ) : ''}
    </div>
  )
}